import{_ as i,c as r,o as n,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.58: TUI Interaction Optimization","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.58.md","filePath":"en/changelog/v1.1.58.md","lastUpdated":1772014034000}'),o={name:"en/changelog/v1.1.58.md"};function s(l,a,d,h,c,p){return n(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-1-58-tui-interaction-optimization" tabindex="-1">v1.1.58: TUI Interaction Optimization <a class="header-anchor" href="#v1-1-58-tui-interaction-optimization" aria-label="Permalink to “v1.1.58: TUI Interaction Optimization”">​</a></h1><p><strong>Release Date</strong>: February 11, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update <strong>optimizes terminal interface (TUI) interaction experience</strong>, supports Ctrl+C to close dialogs, different modes show different input prompts, share links can be copied repeatedly.</p><hr><h2 id="new-feature-ctrl-c-to-close-dialogs" tabindex="-1">New Feature: Ctrl+C to Close Dialogs <a class="header-anchor" href="#new-feature-ctrl-c-to-close-dialogs" aria-label="Permalink to “New Feature: Ctrl+C to Close Dialogs”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>In TUI, you can now use <strong>Ctrl+C to close various dialogs</strong>, no need to find the Escape key.</p><h3 id="why-important" tabindex="-1">Why Important? <a class="header-anchor" href="#why-important" aria-label="Permalink to “Why Important?”">​</a></h3><p>Previously closing dialogs only worked with Escape. Now Ctrl+C also works, more intuitive.</p><hr><h2 id="new-feature-mode-specific-input-prompts" tabindex="-1">New Feature: Mode-Specific Input Prompts <a class="header-anchor" href="#new-feature-mode-specific-input-prompts" aria-label="Permalink to “New Feature: Mode-Specific Input Prompts”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Input box placeholder text now changes based on current mode, telling you what to input.</p><h3 id="effect-example" tabindex="-1">Effect Example <a class="header-anchor" href="#effect-example" aria-label="Permalink to “Effect Example”">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Placeholder Text</th></tr></thead><tbody><tr><td>Default mode</td><td>&quot;Ask me anything...&quot;</td></tr><tr><td>Code mode</td><td>&quot;Describe the feature you want...&quot;</td></tr><tr><td>Plan mode</td><td>&quot;Describe your project requirements...&quot;</td></tr></tbody></table><p>This way you can clearly know how to ask questions in the current mode.</p><hr><h2 id="new-feature-share-links-can-be-copied-repeatedly" tabindex="-1">New Feature: Share Links Can Be Copied Repeatedly <a class="header-anchor" href="#new-feature-share-links-can-be-copied-repeatedly" aria-label="Permalink to “New Feature: Share Links Can Be Copied Repeatedly”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>After using <code>/share</code> command to share a session, if you wanted to copy the link again, you needed to regenerate it.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p><code>/share</code> command now stays available, you can copy the generated share link anytime without regenerating.</p><hr><h2 id="improvement-home-interface-adaptive" tabindex="-1">Improvement: Home Interface Adaptive <a class="header-anchor" href="#improvement-home-interface-adaptive" aria-label="Permalink to “Improvement: Home Interface Adaptive”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>In terminals with limited height, Home interface text might display abnormally.</p><h3 id="current-status-1" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-1" aria-label="Permalink to “Current Status”">​</a></h3><p>Fixed the issue where Home interface text displayed corrupted in height-limited terminals.</p><hr><h2 id="bug-fix-desktop" tabindex="-1">Bug Fix: Desktop <a class="header-anchor" href="#bug-fix-desktop" aria-label="Permalink to “Bug Fix: Desktop”">​</a></h2><h3 id="sub-session-notifications" tabindex="-1">Sub-session Notifications <a class="header-anchor" href="#sub-session-notifications" aria-label="Permalink to “Sub-session Notifications”">​</a></h3><p>Sub-sessions (Forked sessions) can now also display notifications.</p><h3 id="terminal-buffer" tabindex="-1">Terminal Buffer <a class="header-anchor" href="#terminal-buffer" aria-label="Permalink to “Terminal Buffer”">​</a></h3><p>Terminal PTY buffer is now correctly preserved between sessions, switching sessions won&#39;t lose previous output.</p><h3 id="terminal-resize" tabindex="-1">Terminal Resize <a class="header-anchor" href="#terminal-resize" aria-label="Permalink to “Terminal Resize”">​</a></h3><p>Fixed terminal resize issue in desktop app.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Frequently use TUI</td><td>✅ Upgrade</td></tr><tr><td>Need to share sessions</td><td>✅ Upgrade</td></tr><tr><td>Only using desktop</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',42),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Support Ctrl+C to close dialogs</li><li>Keep /share command available to copy existing links</li><li>Add mode-specific input prompts</li><li>Fix Home interface text corruption in height-limited terminals</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Revert WSL backend mode feature</li><li>Enable notifications for sub-sessions</li><li>Terminal PTY buffer correctly preserved between sessions</li><li>Fix terminal resize functionality</li></ul><h3 id="community-contributions" tabindex="-1">Community Contributions <a class="header-anchor" href="#community-contributions" aria-label="Permalink to “Community Contributions”">​</a></h3><ul><li>@kitlangton: TUI interaction optimization (Ctrl+C close dialogs, mode prompts, Home interface fix, share links)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const f=i(o,[["render",s]]);export{m as __pageData,f as default};
